import { Component, OnInit } from '@angular/core';
import { LeaveRequestService } from '../../services/leave-request.service';
import { AuthService } from '../../services/auth.service';
import { LeaveRequest } from '../../models/leave-request.model';

@Component({
  selector: 'app-leave-requests',
  templateUrl: './leave-requests.component.html',
  styleUrls: ['./leave-requests.component.css']
})
export class LeaveRequestsComponent implements OnInit {
  requests: LeaveRequest[] = [];
  currentUser: any;
  showForm = false;
  newRequest: LeaveRequest = { studentId: 0, studentName: '', fromDate: '', toDate: '', reason: '', status: 'PENDING' };

  constructor(private leaveService: LeaveRequestService, private authService: AuthService) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadRequests();
  }

  loadRequests() {
    if (this.currentUser.role === 'STUDENT') {
      this.leaveService.getLeaveRequestsByStudent(this.currentUser.id).subscribe(data => this.requests = data);
    } else {
      this.leaveService.getAllLeaveRequests().subscribe(data => this.requests = data);
    }
  }

  createRequest() {
    this.newRequest.studentId = this.currentUser.id;
    this.newRequest.studentName = this.currentUser.firstName + ' ' + this.currentUser.lastName;
    this.leaveService.createLeaveRequest(this.newRequest).subscribe(() => {
      this.loadRequests();
      this.showForm = false;
      alert('Leave request submitted!');
    });
  }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <div class="d-flex justify-content-between mb-4">
      <h2>Leave Requests</h2>
      <button class="btn btn-primary" *ngIf="currentUser?.role === 'STUDENT'" (click)="showForm = !showForm">
        {{ showForm ? 'Cancel' : '+ New Request' }}
      </button>
    </div>

    <div *ngIf="showForm" class="card mb-4">
      <div class="card-body">
        <form (ngSubmit)="createRequest()">
          <div class="row">
            <div class="col-md-6 mb-3">
              <label class="form-label">From Date</label>
              <input type="date" class="form-control" [(ngModel)]="newRequest.fromDate" name="fromDate" required>
            </div>
            <div class="col-md-6 mb-3">
              <label class="form-label">To Date</label>
              <input type="date" class="form-control" [(ngModel)]="newRequest.toDate" name="toDate" required>
            </div>
          </div>
          <div class="mb-3">
            <label class="form-label">Reason</label>
            <textarea class="form-control" [(ngModel)]="newRequest.reason" name="reason" rows="3" required></textarea>
          </div>
          <button type="submit" class="btn btn-success">Submit Request</button>
        </form>
      </div>
    </div>

    <div class="table-responsive">
      <table class="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Student</th>
            <th>From Date</th>
            <th>To Date</th>
            <th>Reason</th>
            <th>Status</th>
            <th>Created</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let req of requests">
            <td>{{ req.id }}</td>
            <td>{{ req.studentName }}</td>
            <td>{{ req.fromDate }}</td>
            <td>{{ req.toDate }}</td>
            <td>{{ req.reason }}</td>
            <td><span class="badge" [ngClass]="{'bg-success': req.status === 'APPROVED', 'bg-danger': req.status === 'REJECTED', 'bg-warning': req.status === 'PENDING'}">
              {{ req.status }}</span></td>
            <td>{{ req.createdAt | date:'short' }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
